 50→void parity_init(void)
 51→{
 52→	if (parity_initialized) return;
 53→	parity_initialized = 1;
 54→
 55→	const char *assert_env = getenv("OX_PARITY_ASSERT");
 56→	if (assert_env && atoi(assert_env))
 57→		parity_assert_on_diverge = 1;
 58→
 59→	const char *log_env = getenv("OX_PARITY_LOG");
 60→	if (log_env && log_env[0]) {
 61→		parity_log_file = fopen(log_env, "w");
 62→		if (!parity_log_file)
 63→			fprintf(stderr, "PARITY: failed to open log file '%s'\n", log_env);
 64→	}
 65→
 66→	fprintf(stderr, "PARITY: initialized (assert=%d, log=%s)\n",
 67→		parity_assert_on_diverge,
 68→		log_env ? log_env : "stderr");
 69→}
