    int divergences = 0;
    int a_val, b_val;
    char prefix[64];
    snprintf(prefix, sizeof(prefix), "Ai_local[%d]", idx);

    CMP_FIELD(prefix, player_awareness_type, aa->player_awareness_type, ab->player_awareness_type);
