					vms_matrix m;
					vm_vector_2_matrix(&m, &fwd, &up, nullptr);
					out[0] = m.rvec.x; out[1] = m.rvec.y; out[2] = m.rvec.z;
					out[3] = m.uvec.x; out[4] = m.uvec.y; out[5] = m.uvec.z;
